 /// @param position - index into var_refs array
 /// @param val - value to set (ownership transferred)
 pub inline fn setClosureVar(ctx: *JSContext, var_refs: ?[*]*JSVarRef, position: u32, val: JSValue) void {
-    if (var_refs) |refs| {
